// src/components/Header.js
import React, { useState, useRef, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

// SVG avatar icon
const AvatarIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="42" height="42" viewBox="0 0 16 16">
    <g transform="translate(0 -1036.362)">
      <circle cx="8" cy="1044.362" r="8" fill="#1d67b1" />
      <path fill="#2a2f3c" d="M5.978 1046.475H10v.965H5.978z" />
      <path fill="#272a4d" d="M7.186 1039.854h1.81c.823 0 1.486.74 1.486 1.658 0 .918-.663 1.657-1.486 1.657h-1.81c-.824 0-1.487-.74-1.487-1.657 0-.918.663-1.657 1.487-1.657z" />
      {/* ...restante do SVG omitido para brevidade... */}
    </g>
  </svg>
);

export default function Header() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [open, setOpen] = useState(false);

  // refs para detectar clicks fora
  const btnRef = useRef(null);
  const menuRef = useRef(null);

  // extrai o primeiro nome
  const fullName = user?.usuario || 'Usuário';
  const firstName = fullName.split(' ')[0];

  // alterna o dropdown
  const toggle = () => setOpen(o => !o);

  // Fecha se clicar fora
  useEffect(() => {
    function handleOutside(e) {
      if (
        open &&
        menuRef.current &&
        !menuRef.current.contains(e.target) &&
        btnRef.current &&
        !btnRef.current.contains(e.target)
      ) {
        setOpen(false);
      }
    }
    document.addEventListener('mousedown', handleOutside);
    return () => document.removeEventListener('mousedown', handleOutside);
  }, [open]);

  const goProfile = () => {
    setOpen(false);
    navigate('/perfil');
  };
  const doLogout = () => {
    setOpen(false);
    logout();
    navigate('/login', { replace: true });
  };

  return (
    <header className="fixed top-0 left-0 right-0 h-16 bg-white shadow flex items-center justify-start px-6 z-50 space-x-6">
      {/* nome à esquerda do avatar */}
      <div className="relative flex items-center">
        <span className="mr-2 text-black font-medium">{firstName}</span>
        <button
          ref={btnRef}
          onClick={toggle}
          className="rounded-full focus:outline-none focus:ring-2 focus:ring-blue-400"
        >
          <AvatarIcon />
        </button>

        {open && (
          <ul
            ref={menuRef}
            className="absolute right-0 mt-2 w-48 bg-white border border-gray-200 rounded-lg shadow-lg"
          >
            <li className="px-4 py-2 text-black font-medium border-b border-gray-100">
              {firstName}
            </li>
            <li>
              <button
                onClick={goProfile}
                className="w-full text-left px-4 py-2 hover:bg-gray-100 text-black"
              >
                Meu Perfil
              </button>
            </li>
            <li>
              <button
                onClick={doLogout}
                className="w-full text-left px-4 py-2 hover:bg-gray-100 text-red-600"
              >
                Sair
              </button>
            </li>
          </ul>
        )}
      </div>

      {/* título do app */}
      <h1 className="text-xl font-bold text-[#3172C0] flex-grow">
        PoliUB Atendimentos
      </h1>
    </header>
  );
}
